// Validar payload da Evolution API e extrair dados da mensagem
const payload = $input.first().json;

// Só processar mensagens recebidas
if (payload.event !== 'messages.upsert') return [];
const data = payload.data;
if (!data?.key) return [];
if (data.key.fromMe === true) return [];  // ignorar mensagens do próprio bot

const remoteJid = data.key.remoteJid ?? '';
if (!remoteJid.endsWith('@s.whatsapp.net')) return [];  // ignorar grupos

// Extrair texto
const msg = data.message;
const text = (
  msg?.conversation ??
  msg?.extendedTextMessage?.text ??
  msg?.imageMessage?.caption ??
  msg?.videoMessage?.caption ??
  null
);

if (!text?.trim()) return [];

return [{
  json: {
    instanceName: payload.instance,
    phone: remoteJid.replace('@s.whatsapp.net', ''),
    senderName: data.pushName ?? '',
    text: text.trim()
  }
}];

// Carregar todos os dados necessários do Supabase em paralelo
const { instanceName, phone, senderName, text } = $input.first().json;

const BASE = $env.SUPABASE_URL.replace(/\/$/, '');
const KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const H = { apikey: KEY, Authorization: `Bearer ${KEY}`, 'Content-Type': 'application/json' };

// 1. Buscar configuração da instância WhatsApp
const cfgRes = await fetch(
  `${BASE}/rest/v1/whatsapp_config?instance_name=eq.${encodeURIComponent(instanceName)}&select=clinic_id,is_active,auto_booking,agent_instructions`,
  { headers: H }
);
const configs = await cfgRes.json();
const config = configs[0] ?? null;

if (!config) {
  console.log(`[lorvix] Instância não encontrada: ${instanceName}`);
  return [];
}

const clinicId = config.clinic_id;

// 2. Buscar clínica, serviços, profissionais e histórico em paralelo
const [clinicRes, svcRes, prosRes, histRes] = await Promise.all([
  fetch(`${BASE}/rest/v1/clinics?id=eq.${clinicId}&select=name,phone,email,address`, { headers: H }),
  fetch(`${BASE}/rest/v1/services?clinic_id=eq.${clinicId}&is_active=eq.true&select=id,name,description,duration_minutes,price,category&order=name`, { headers: H }),
  fetch(`${BASE}/rest/v1/professionals?clinic_id=eq.${clinicId}&is_active=eq.true&select=id,name,specialty&order=name`, { headers: H }),
  fetch(`${BASE}/rest/v1/whatsapp_conversations?clinic_id=eq.${clinicId}&phone=eq.${phone}&select=id,messages`, { headers: H })
]);

const [clinics, services, professionals, convs] = await Promise.all([
  clinicRes.json(), svcRes.json(), prosRes.json(), histRes.json()
]);

const conv = convs[0] ?? null;

return [{
  json: {
    instanceName,
    phone,
    senderName,
    text,
    clinicId,
    is_active: Boolean(config.is_active),
    auto_booking: Boolean(config.auto_booking),
    agent_instructions: config.agent_instructions ?? '',
    clinic: clinics[0] ?? null,
    services: services ?? [],
    professionals: professionals ?? [],
    conv_id: conv?.id ?? null,
    history: Array.isArray(conv?.messages) ? conv.messages.slice(-20) : []
  }
}];

// Loop completo do agente IA com tool calling
const ctx = $('Carregar Contexto').first().json;

const BASE = $env.SUPABASE_URL.replace(/\/$/, '');
const KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const OPENAI_KEY = $env.OPENAI_API_KEY;
const MODEL = $env.OPENAI_MODEL || 'gpt-4o-mini';

const {
  clinicId, auto_booking, agent_instructions,
  clinic, services, professionals,
  history, text, senderName, phone,
  instanceName, conv_id
} = ctx;

// ── Montar prompt do sistema ─────────────────────────────────────────────────
const today = new Date().toLocaleDateString('pt-BR', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric',
  timeZone: 'America/Sao_Paulo'
});

const svcList = Array.isArray(services) && services.length
  ? services.map(s =>
      `  • ${s.name}` +
      (s.duration_minutes ? ` (${s.duration_minutes}min)` : '') +
      (s.price ? ` – R$${Number(s.price).toFixed(2)}` : '') +
      (s.description ? ': ' + s.description : '')
    ).join('\n')
  : '  (não cadastrados — use get_available_slots para consultar)';

const proList = Array.isArray(professionals) && professionals.length
  ? professionals.map(p => `  • ${p.name} – ${p.specialty} [id: ${p.id}]`).join('\n')
  : '  (nenhum profissional cadastrado)';

const bookingRule = auto_booking
  ? 'Você PODE criar, remarcar e cancelar agendamentos usando as ferramentas.'
  : 'Agendamento automático DESATIVADO. Consulte horários, mas oriente o paciente a ligar ou acessar o sistema para agendar.';

const systemPrompt =
  `Você é a assistente virtual da ${clinic?.name ?? 'clínica'}, atendendo pelo WhatsApp.\n` +
  `Data atual: ${today}.\n` +
  (senderName ? `O paciente se chama ${senderName}.\n` : '') +
  `Telefone do paciente: ${phone}\n\n` +
  `SERVIÇOS DISPONÍVEIS:\n${svcList}\n\n` +
  `PROFISSIONAIS:\n${proList}\n\n` +
  `REGRAS:\n` +
  `- Responda SEMPRE em português brasileiro.\n` +
  `- Seja cordial, objetivo e profissional.\n` +
  `- Nunca invente informações — use as ferramentas para dados reais.\n` +
  `- Ao apresentar horários, liste de forma organizada (09:00, 09:30...).\n` +
  `- Antes de agendar, confirme: serviço, profissional, data e horário.\n` +
  `- ${bookingRule}\n\n` +
  `FLUXO DE AGENDAMENTO:\n` +
  `1. Entenda a necessidade.\n` +
  `2. Verifique disponibilidade com get_available_slots.\n` +
  `3. Confirme dados com o paciente.\n` +
  `4. Execute create_appointment.\n` +
  `5. Confirme o agendamento ao paciente.` +
  (agent_instructions ? `\n\nINSTRUÇÕES DA CLÍNICA:\n${agent_instructions}` : '');

// ── Definição das ferramentas ────────────────────────────────────────────────
const tools = [
  {
    type: 'function',
    function: {
      name: 'get_available_slots',
      description: 'Retorna horários disponíveis para agendamento em uma data específica.',
      parameters: {
        type: 'object',
        properties: {
          date: { type: 'string', description: 'Data no formato YYYY-MM-DD.' },
          professional_id: { type: 'string', description: 'ID do profissional (opcional).' }
        },
        required: ['date']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'get_patient_appointments',
      description: 'Lista os próximos agendamentos de um paciente pelo telefone.',
      parameters: {
        type: 'object',
        properties: {
          phone: { type: 'string', description: 'Telefone do paciente, apenas dígitos.' }
        },
        required: ['phone']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'create_appointment',
      description: 'Cria um agendamento. Confirme TODOS os dados com o paciente antes de chamar.',
      parameters: {
        type: 'object',
        properties: {
          patient_phone:   { type: 'string', description: 'Telefone do paciente, apenas dígitos.' },
          patient_name:    { type: 'string', description: 'Nome completo do paciente.' },
          service:         { type: 'string', description: 'Nome do serviço.' },
          date:            { type: 'string', description: 'Data YYYY-MM-DD.' },
          time:            { type: 'string', description: 'Horário HH:MM.' },
          professional_id: { type: 'string', description: 'ID do profissional (opcional).' },
          notes:           { type: 'string', description: 'Observações (opcional).' }
        },
        required: ['patient_phone', 'patient_name', 'service', 'date', 'time']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'cancel_appointment',
      description: 'Cancela um agendamento existente. Confirme com o paciente antes.',
      parameters: {
        type: 'object',
        properties: {
          appointment_id: { type: 'string', description: 'ID do agendamento a cancelar.' }
        },
        required: ['appointment_id']
      }
    }
  },
  {
    type: 'function',
    function: {
      name: 'reschedule_appointment',
      description: 'Remarca um agendamento para nova data e horário.',
      parameters: {
        type: 'object',
        properties: {
          appointment_id: { type: 'string', description: 'ID do agendamento.' },
          new_date:       { type: 'string', description: 'Nova data YYYY-MM-DD.' },
          new_time:       { type: 'string', description: 'Novo horário HH:MM.' }
        },
        required: ['appointment_id', 'new_date', 'new_time']
      }
    }
  }
];

// ── Execução das ferramentas ─────────────────────────────────────────────────
const SBH = {
  apikey: KEY,
  Authorization: `Bearer ${KEY}`,
  'Content-Type': 'application/json',
  Prefer: 'return=representation'
};

async function runTool(name, args) {

  // ── get_available_slots ──────────────────────────────────────────────────
  if (name === 'get_available_slots') {
    const { date, professional_id } = args;
    const dow = new Date(date + 'T12:00:00').getDay();
    let availUrl = `${BASE}/rest/v1/availability?clinic_id=eq.${clinicId}&day_of_week=eq.${dow}&select=professional_id,start_time,end_time,slot_duration`;
    if (professional_id) availUrl += `&professional_id=eq.${professional_id}`;

    const [aRes, apptRes, blkRes] = await Promise.all([
      fetch(availUrl, { headers: SBH }),
      fetch(`${BASE}/rest/v1/appointments?clinic_id=eq.${clinicId}&start_datetime=gte.${date}T00:00:00&start_datetime=lte.${date}T23:59:59&status=neq.cancelled&select=professional_id,start_datetime,end_datetime`, { headers: SBH }),
      fetch(`${BASE}/rest/v1/schedule_blocks?clinic_id=eq.${clinicId}&start_datetime=lte.${date}T23:59:59&end_datetime=gte.${date}T00:00:00&select=professional_id,start_datetime,end_datetime`, { headers: SBH })
    ]);
    const [avail, appts, blocks] = await Promise.all([aRes.json(), apptRes.json(), blkRes.json()]);
    const busy = [...(appts ?? []), ...(blocks ?? [])];

    const slotMap = {};
    for (const rule of (avail ?? [])) {
      const [sh, sm] = rule.start_time.split(':').map(Number);
      const [eh, em] = rule.end_time.split(':').map(Number);
      const dur = rule.slot_duration ?? 30;
      let ch = sh, cm = sm;
      while (ch * 60 + cm + dur <= eh * 60 + em) {
        const hh = String(ch).padStart(2, '0');
        const mm = String(cm).padStart(2, '0');
        const slotStart = new Date(`${date}T${hh}:${mm}:00`).getTime();
        const slotEnd = slotStart + dur * 60000;
        const conflict = busy.some(b => {
          const bs = new Date(b.start_datetime).getTime();
          const be = new Date(b.end_datetime).getTime();
          return slotStart < be && slotEnd > bs && b.professional_id === rule.professional_id;
        });
        const key = `${hh}:${mm}`;
        if (!conflict && !slotMap[key]) slotMap[key] = { time: key, professional_id: rule.professional_id };
        cm += dur;
        while (cm >= 60) { cm -= 60; ch++; }
      }
    }
    const slots = Object.values(slotMap).sort((a, b) => a.time.localeCompare(b.time));
    return { date, slots, total: slots.length };
  }

  // ── get_patient_appointments ─────────────────────────────────────────────
  if (name === 'get_patient_appointments') {
    const digits = (args.phone || phone).replace(/\D/g, '');
    const pRes = await fetch(`${BASE}/rest/v1/patients?clinic_id=eq.${clinicId}&phone=eq.${digits}&select=id`, { headers: SBH });
    const patients = await pRes.json();
    if (!patients?.[0]) return { appointments: [], message: 'Paciente não cadastrado.' };
    const aRes = await fetch(
      `${BASE}/rest/v1/appointments?clinic_id=eq.${clinicId}&patient_id=eq.${patients[0].id}&status=neq.cancelled&start_datetime=gte.${new Date().toISOString()}&select=id,service,start_datetime,status&order=start_datetime&limit=5`,
      { headers: SBH }
    );
    const appointments = await aRes.json();
    return { appointments: appointments ?? [] };
  }

  // ── create_appointment ───────────────────────────────────────────────────
  if (name === 'create_appointment') {
    if (!auto_booking) return { error: 'Agendamento automático desativado. Oriente o paciente a ligar.' };
    const { patient_phone, patient_name, service: svcName, date, time, professional_id, notes } = args;
    const digits = patient_phone.replace(/\D/g, '');

    // Encontrar ou criar paciente
    const pRes = await fetch(`${BASE}/rest/v1/patients?clinic_id=eq.${clinicId}&phone=eq.${digits}&select=id,full_name`, { headers: SBH });
    const found = await pRes.json();
    let patientId = found?.[0]?.id;
    if (!patientId) {
      const cRes = await fetch(`${BASE}/rest/v1/patients`, {
        method: 'POST', headers: SBH,
        body: JSON.stringify({ clinic_id: clinicId, full_name: patient_name, phone: digits })
      });
      const created = await cRes.json();
      patientId = created?.[0]?.id;
    }
    if (!patientId) return { error: 'Erro ao cadastrar paciente.' };

    // Resolver profissional
    let profId = professional_id;
    if (!profId && professionals?.[0]) profId = professionals[0].id;
    if (!profId) return { error: 'Nenhum profissional disponível.' };

    // Resolver duração pelo serviço cadastrado
    const svc = services?.find(s => s.name?.toLowerCase().includes(svcName?.toLowerCase()));
    const dur = svc?.duration_minutes ?? 30;
    const start = new Date(`${date}T${time}:00`);
    const end = new Date(start.getTime() + dur * 60000);

    const aRes = await fetch(`${BASE}/rest/v1/appointments`, {
      method: 'POST', headers: SBH,
      body: JSON.stringify({
        clinic_id: clinicId, patient_id: patientId, professional_id: profId,
        service: svcName, start_datetime: start.toISOString(), end_datetime: end.toISOString(),
        status: 'scheduled', source: 'whatsapp', notes: notes ?? null
      })
    });
    const appt = await aRes.json();
    if (appt?.code === '23P01' || appt?.code?.startsWith('23')) return { error: 'Conflito de horário. Escolha outro horário.' };
    return { success: true, appointment_id: appt?.[0]?.id, date, time, service: svcName, duration_minutes: dur };
  }

  // ── cancel_appointment ───────────────────────────────────────────────────
  if (name === 'cancel_appointment') {
    if (!auto_booking) return { error: 'Cancelamento automático desativado.' };
    const r = await fetch(`${BASE}/rest/v1/appointments?id=eq.${args.appointment_id}&clinic_id=eq.${clinicId}`, {
      method: 'PATCH', headers: SBH,
      body: JSON.stringify({ status: 'cancelled' })
    });
    return r.ok ? { success: true } : { error: 'Erro ao cancelar agendamento.' };
  }

  // ── reschedule_appointment ───────────────────────────────────────────────
  if (name === 'reschedule_appointment') {
    if (!auto_booking) return { error: 'Remarcação automática desativada.' };
    const { appointment_id, new_date, new_time } = args;
    const aRes = await fetch(`${BASE}/rest/v1/appointments?id=eq.${appointment_id}&clinic_id=eq.${clinicId}&select=start_datetime,end_datetime`, { headers: SBH });
    const appts = await aRes.json();
    if (!appts?.[0]) return { error: 'Agendamento não encontrado.' };
    const dur = new Date(appts[0].end_datetime).getTime() - new Date(appts[0].start_datetime).getTime();
    const newStart = new Date(`${new_date}T${new_time}:00`);
    const newEnd = new Date(newStart.getTime() + dur);
    const r = await fetch(`${BASE}/rest/v1/appointments?id=eq.${appointment_id}&clinic_id=eq.${clinicId}`, {
      method: 'PATCH', headers: SBH,
      body: JSON.stringify({ start_datetime: newStart.toISOString(), end_datetime: newEnd.toISOString(), status: 'scheduled' })
    });
    return r.ok ? { success: true, new_date, new_time } : { error: 'Erro ao remarcar.' };
  }

  return { error: `Ferramenta desconhecida: ${name}` };
}

// ── Loop do agente ───────────────────────────────────────────────────────────
const messages = [
  { role: 'system', content: systemPrompt },
  ...history.map(m => ({ role: m.role, content: m.content }))
];
messages.push({ role: 'user', content: text });

let reply = 'Desculpe, não consegui processar sua mensagem. Entre em contato diretamente com a clínica.';

for (let round = 0; round < 8; round++) {
  const res = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${OPENAI_KEY}` },
    body: JSON.stringify({
      model: MODEL,
      messages,
      tools,
      tool_choice: 'auto',
      max_tokens: 1024,
      temperature: 0.4
    })
  });

  const data = await res.json();
  if (data.error) {
    console.error('[lorvix-agent] OpenAI erro:', JSON.stringify(data.error));
    break;
  }

  const choice = data.choices?.[0];
  if (!choice) break;

  // Sem tool calls — resposta final
  if (!choice.message?.tool_calls?.length) {
    reply = choice.message.content ?? reply;
    break;
  }

  // Processar tool calls
  messages.push(choice.message);
  for (const tc of choice.message.tool_calls) {
    let args = {};
    try { args = JSON.parse(tc.function.arguments); } catch {}
    console.log(`[tool] ${tc.function.name}:`, JSON.stringify(args));
    const result = await runTool(tc.function.name, args);
    console.log(`[tool] resultado:`, JSON.stringify(result));
    messages.push({ role: 'tool', tool_call_id: tc.id, content: JSON.stringify(result) });
  }
}

// Atualizar histórico
const newHistory = [
  ...history,
  { role: 'user', content: text, timestamp: new Date().toISOString() },
  { role: 'assistant', content: reply, timestamp: new Date().toISOString() }
].slice(-30);

return [{ json: { reply, phone, instanceName, clinicId, conv_id, history: newHistory } }];

// Salvar ou atualizar histórico da conversa no Supabase
const { clinicId, phone, conv_id, history } = $('Agente IA').first().json;

const BASE = $env.SUPABASE_URL.replace(/\/$/, '');
const KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const H = {
  apikey: KEY,
  Authorization: `Bearer ${KEY}`,
  'Content-Type': 'application/json',
  Prefer: 'return=representation'
};

if (conv_id) {
  await fetch(`${BASE}/rest/v1/whatsapp_conversations?id=eq.${conv_id}`, {
    method: 'PATCH',
    headers: H,
    body: JSON.stringify({ messages: history, last_message_at: new Date().toISOString() })
  });
} else {
  await fetch(`${BASE}/rest/v1/whatsapp_conversations`, {
    method: 'POST',
    headers: H,
    body: JSON.stringify({
      clinic_id: clinicId,
      phone,
      messages: history,
      last_message_at: new Date().toISOString()
    })
  });
}

return [{ json: { ok: true } }];
